INSERT INTO RF_Tabla_Desarrollo_Interna ( Fec_Pro, Cod_Emp, Moneda, Cod_A_P, Cod_Pro, Cod_Sub_Pro, Fec_Pago, Dias_Pago, Cap_Amort, Int_Total_Cont, VP_Cap_Amort, VP_Int_Total_Cont, Precio_Mid, Flujo_CLP )
SELECT RF_PLI_Modelo_Inversiones_Final_CLP.Fec_Pro, RF_PLI_Modelo_Inversiones_Final_CLP.Cod_Emp, RF_PLI_Modelo_Inversiones_Final_CLP.Moneda, RF_PLI_Modelo_Inversiones_Final_CLP.Cod_A_P, RF_PLI_Modelo_Inversiones_Final_CLP.Cod_Pro, RF_PLI_Modelo_Inversiones_Final_CLP.Cod_Sub_Pro, RF_PLI_Modelo_Inversiones_Final_CLP.Fec_Pago, RF_PLI_Modelo_Inversiones_Final_CLP.Dias_Pago, RF_PLI_Modelo_Inversiones_Final_CLP.Cap_Amort, RF_PLI_Modelo_Inversiones_Final_CLP.Int_Total_Cont, RF_PLI_Modelo_Inversiones_Final_CLP.VP_Cap_Amort, RF_PLI_Modelo_Inversiones_Final_CLP.VP_Int_Total_Cont, Precios_Dia.Precio_Mid, ([RF_PLI_Modelo_Inversiones_Final_CLP].[VP_Cap_Amort]+[RF_PLI_Modelo_Inversiones_Final_CLP].[VP_Int_Total_Cont])*[Precios_Dia].[Precio_Mid] AS Flujo_CLP
FROM Precios_Dia INNER JOIN RF_PLI_Modelo_Inversiones_Final_CLP ON Precios_Dia.NEMOTECNICO = RF_PLI_Modelo_Inversiones_Final_CLP.Moneda;
